import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

const NewsContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem;
`;

const PageTitle = styled(motion.h1)`
  font-size: 2.5rem;
  margin-bottom: 2rem;
  text-align: center;
  background: linear-gradient(45deg, #ff6b6b, #4ecdc4);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
`;

const NewsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const NewsCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 1.5rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
  }
`;

const NewsTitle = styled.h3`
  font-size: 1.2rem;
  margin-bottom: 1rem;
  color: #ffffff;
`;

const NewsContent = styled.p`
  color: #cccccc;
  line-height: 1.6;
`;

const NewsDate = styled.span`
  color: #4ecdc4;
  font-size: 0.9rem;
`;

const newsItems = [
  {
    title: 'ЁЯУИ Stock Market Hits All-Time High',
    content: 'Major indices reached record levels as investor confidence grows amid economic recovery.',
    date: 'March 4, 2026'
  },
  {
    title: 'ЁЯТ░ Gold Prices Surge 5%',
    content: 'Precious metals see strong demand as investors seek safe-haven assets.',
    date: 'March 3, 2026'
  },
  {
    title: 'ЁЯМН Global Economic Outlook Improves',
    content: 'IMF revises growth forecasts upward as key economies show resilience.',
    date: 'March 2, 2026'
  },
  {
    title: 'ЁЯТ╝ Portfolio Diversification Tips',
    content: 'Expert advice on building a balanced investment portfolio in uncertain times.',
    date: 'March 1, 2026'
  },
  {
    title: 'ЁЯУК Tech Stocks Lead Market Rally',
    content: 'Technology sector continues to outperform as innovation drives growth.',
    date: 'February 28, 2026'
  },
  {
    title: 'ЁЯФТ Security Best Practices for Investors',
    content: 'How to protect your financial accounts and personal information online.',
    date: 'February 27, 2026'
  }
];

const News: React.FC = () => {
  return (
    <NewsContainer>
      <PageTitle
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        ЁЯУ░ Financial News
      </PageTitle>

      <NewsGrid>
        {newsItems.map((news, index) => (
          <NewsCard
            key={index}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
            whileHover={{ scale: 1.02 }}
          >
            <NewsTitle>{news.title}</NewsTitle>
            <NewsContent>{news.content}</NewsContent>
            <NewsDate>{news.date}</NewsDate>
          </NewsCard>
        ))}
      </NewsGrid>
    </NewsContainer>
  );
};

export default News;
